# solution.py
"""
MultiAgentBudgetOptimizer
=========================

A collaborative, multi-user budget management and optimization application.

Features
--------
* **Multiple user accounts** -- every member can record expenses, view the
  shared budget and inspect the overall financial status of the group.
* **Dashboard** -- a summary of the group's total expenses, remaining budget,
  per-category utilization and the individual contribution of every member.
* **Per-category budget limits** (e.g. groceries, entertainment, utilities)
  that can be created, adjusted or removed at any time.
* **Collaborative optimization engine** -- suggests how to reallocate budget
  from under-used categories to over-spent ones and which concrete expenses to
  trim in order to reach the group's savings goal.
* **Robust input validation** -- every public operation defends against invalid
  data such as unknown users/categories and negative / non-numeric amounts.

The module is intentionally self-contained: the implementation and an extensive
``unittest`` suite live side by side so the file can be executed directly::

    python solution.py          # run an interactive demonstration
    python solution.py test     # run the full unit-test suite
"""

from __future__ import annotations

import math
import sys
import unittest
from dataclasses import dataclass, field
from datetime import datetime
from typing import Dict, List, Optional


# --------------------------------------------------------------------------- #
#  Exceptions
# --------------------------------------------------------------------------- #
class BudgetError(Exception):
    """Base class for every error raised by the budget optimizer."""


class ValidationError(BudgetError):
    """Raised when a supplied value fails validation."""


class UserError(BudgetError):
    """Raised for problems related to user accounts."""


class CategoryError(BudgetError):
    """Raised for problems related to budget categories."""


# --------------------------------------------------------------------------- #
#  Validation / helper utilities
# --------------------------------------------------------------------------- #
def _money(value: float) -> float:
    """Round a monetary value to cent precision (2 decimals)."""
    return round(float(value), 2)


def _validate_number(value, *, name: str = "value") -> float:
    """Validate that *value* is a finite number (any sign). Returns a float."""
    if isinstance(value, bool):  # bool is a subclass of int -> reject explicitly
        raise ValidationError(f"{name} must be a number, not a boolean")
    try:
        result = float(value)
    except (TypeError, ValueError):
        raise ValidationError(f"{name} must be a number, got {value!r}")
    if math.isnan(result) or math.isinf(result):
        raise ValidationError(f"{name} must be a finite number")
    return _money(result)


def _validate_amount(value, *, allow_zero: bool = False, name: str = "amount") -> float:
    """Validate a monetary amount. By default it must be strictly positive."""
    result = _validate_number(value, name=name)
    if allow_zero:
        if result < 0:
            raise ValidationError(f"{name} must be non-negative, got {result}")
    else:
        if result <= 0:
            raise ValidationError(f"{name} must be greater than zero, got {result}")
    return result


def _validate_name(value, *, kind: str = "name") -> str:
    """Validate that *value* is a non-empty string and return it stripped."""
    if not isinstance(value, str):
        raise ValidationError(
            f"{kind} must be a string, got {type(value).__name__}"
        )
    cleaned = value.strip()
    if not cleaned:
        raise ValidationError(f"{kind} must not be empty")
    return cleaned


def _norm_category(value) -> str:
    """Normalise a category name (stripped + lower-cased for case-insensitivity)."""
    return _validate_name(value, kind="category").lower()


# --------------------------------------------------------------------------- #
#  Domain models
# --------------------------------------------------------------------------- #
@dataclass(frozen=True)
class Expense:
    """A single expense recorded by a user against a budget category."""

    user: str
    category: str
    amount: float
    description: str = ""
    timestamp: datetime = field(default_factory=datetime.now, compare=False)


@dataclass
class User:
    """A user account that owns a list of expenses."""

    name: str
    expenses: List[Expense] = field(default_factory=list)

    @property
    def total_spent(self) -> float:
        return _money(sum(e.amount for e in self.expenses))

    def spending_by_category(self) -> Dict[str, float]:
        totals: Dict[str, float] = {}
        for e in self.expenses:
            totals[e.category] = _money(totals.get(e.category, 0.0) + e.amount)
        return totals


# --------------------------------------------------------------------------- #
#  The optimizer
# --------------------------------------------------------------------------- #
class MultiAgentBudgetOptimizer:
    """Coordinate multiple users, budgets and collaborative optimization.

    Parameters
    ----------
    savings_goal:
        Amount of the total budget the group wishes to keep unspent (saved).
        ``goal_met`` is true while ``total_spent <= total_budget - savings_goal``.
    """

    def __init__(self, savings_goal: float = 0.0) -> None:
        self._users: Dict[str, User] = {}
        self._budgets: Dict[str, float] = {}
        self._savings_goal: float = _validate_amount(
            savings_goal, allow_zero=True, name="savings goal"
        )

    # ----------------------------- users ---------------------------------- #
    def add_user(self, name: str) -> User:
        """Register a new user account."""
        clean = _validate_name(name, kind="user name")
        if clean in self._users:
            raise UserError(f"User {clean!r} already exists")
        user = User(clean)
        self._users[clean] = user
        return user

    def remove_user(self, name: str) -> None:
        """Remove a user account (and its expenses)."""
        clean = _validate_name(name, kind="user name")
        if clean not in self._users:
            raise UserError(f"Unknown user {clean!r}")
        del self._users[clean]

    def get_user(self, name: str) -> User:
        clean = _validate_name(name, kind="user name")
        try:
            return self._users[clean]
        except KeyError:
            raise UserError(f"Unknown user {clean!r}")

    @property
    def users(self) -> List[str]:
        return sorted(self._users)

    # ---------------------------- budgets ---------------------------------- #
    def set_budget(self, category: str, limit: float) -> None:
        """Create or replace the budget limit for *category*."""
        cat = _norm_category(category)
        value = _validate_amount(limit, allow_zero=True, name="budget limit")
        self._budgets[cat] = value

    def adjust_budget(self, category: str, delta: float) -> float:
        """Increase (or decrease, for negative *delta*) a category's limit."""
        cat = _norm_category(category)
        if cat not in self._budgets:
            raise CategoryError(f"Unknown category {cat!r}")
        delta_val = _validate_number(delta, name="budget delta")
        new_limit = _money(self._budgets[cat] + delta_val)
        if new_limit < 0:
            raise ValidationError(
                f"Adjusting category {cat!r} by {delta_val} would make the "
                f"limit negative ({new_limit})"
            )
        self._budgets[cat] = new_limit
        return new_limit

    def remove_budget(self, category: str) -> None:
        cat = _norm_category(category)
        if cat not in self._budgets:
            raise CategoryError(f"Unknown category {cat!r}")
        del self._budgets[cat]

    def get_budget(self, category: str) -> float:
        cat = _norm_category(category)
        if cat not in self._budgets:
            raise CategoryError(f"Unknown category {cat!r}")
        return self._budgets[cat]

    @property
    def categories(self) -> List[str]:
        return sorted(self._budgets)

    def total_budget(self) -> float:
        return _money(sum(self._budgets.values()))

    # ------------------------- savings goal -------------------------------- #
    def set_savings_goal(self, amount: float) -> None:
        self._savings_goal = _validate_amount(
            amount, allow_zero=True, name="savings goal"
        )

    @property
    def savings_goal(self) -> float:
        return self._savings_goal

    # ---------------------------- expenses --------------------------------- #
    def add_expense(
        self,
        user: str,
        category: str,
        amount: float,
        description: str = "",
    ) -> Expense:
        """Record an expense for *user* against *category*."""
        u = self.get_user(user)
        cat = _norm_category(category)
        if cat not in self._budgets:
            raise CategoryError(
                f"Unknown category {cat!r}; set a budget for it before "
                f"adding expenses"
            )
        value = _validate_amount(amount, name="expense amount")
        if not isinstance(description, str):
            raise ValidationError("description must be a string")
        expense = Expense(
            user=u.name,
            category=cat,
            amount=value,
            description=description.strip(),
        )
        u.expenses.append(expense)
        return expense

    def all_expenses(self) -> List[Expense]:
        out: List[Expense] = []
        for u in self._users.values():
            out.extend(u.expenses)
        return out

    # --------------------------- aggregation ------------------------------- #
    def spending_by_category(self) -> Dict[str, float]:
        """Total spend per category (only budgeted categories are reported)."""
        totals: Dict[str, float] = {cat: 0.0 for cat in self._budgets}
        for e in self.all_expenses():
            if e.category in totals:
                totals[e.category] += e.amount
        return {cat: _money(value) for cat, value in totals.items()}

    def category_spent(self, category: str) -> float:
        cat = _norm_category(category)
        if cat not in self._budgets:
            raise CategoryError(f"Unknown category {cat!r}")
        return self.spending_by_category().get(cat, 0.0)

    def category_remaining(self, category: str) -> float:
        cat = _norm_category(category)
        return _money(self.get_budget(cat) - self.category_spent(cat))

    def total_spent(self) -> float:
        return _money(sum(e.amount for e in self.all_expenses()))

    def remaining_budget(self) -> float:
        return _money(self.total_budget() - self.total_spent())

    # ------------------------------ views ---------------------------------- #
    def user_view(self, user: str) -> Dict:
        """A single user's personal view of their spending and the group."""
        u = self.get_user(user)
        total = self.total_spent()
        share = _money(100.0 * u.total_spent / total) if total > 0 else 0.0
        return {
            "user": u.name,
            "total_spent": u.total_spent,
            "share_pct": share,
            "num_expenses": len(u.expenses),
            "spending_by_category": u.spending_by_category(),
            "group_total_budget": self.total_budget(),
            "group_remaining_budget": self.remaining_budget(),
        }

    def dashboard(self) -> Dict:
        """A structured snapshot of the whole group's financial status."""
        total_budget = self.total_budget()
        total_spent = self.total_spent()
        spending = self.spending_by_category()

        categories: Dict[str, Dict] = {}
        for cat in sorted(self._budgets):
            limit = self._budgets[cat]
            spent = spending.get(cat, 0.0)
            utilization: Optional[float]
            if limit > 0:
                utilization = _money(100.0 * spent / limit)
            else:
                utilization = None
            categories[cat] = {
                "limit": limit,
                "spent": spent,
                "remaining": _money(limit - spent),
                "over_budget": spent > limit,
                "utilization_pct": utilization,
            }

        users: Dict[str, Dict] = {}
        for name in sorted(self._users):
            u = self._users[name]
            spent = u.total_spent
            share = _money(100.0 * spent / total_spent) if total_spent > 0 else 0.0
            users[name] = {
                "total_spent": spent,
                "share_pct": share,
                "num_expenses": len(u.expenses),
            }

        target_max_spend = _money(total_budget - self._savings_goal)
        return {
            "total_budget": total_budget,
            "total_spent": total_spent,
            "remaining_budget": _money(total_budget - total_spent),
            "savings_goal": self._savings_goal,
            "target_max_spend": target_max_spend,
            "projected_savings": _money(total_budget - total_spent),
            "goal_met": total_spent <= target_max_spend,
            "num_users": len(self._users),
            "num_expenses": len(self.all_expenses()),
            "categories": categories,
            "users": users,
        }

    # -------------------------- optimization ------------------------------- #
    def optimize(self) -> Dict:
        """Suggest reallocations and expense reductions to meet the goal.

        The engine works in two stages:

        1. **Reallocation** -- budget surplus from under-used categories is
           greedily moved to cover over-budget categories.  This keeps the
           *total* budget unchanged: it merely shifts head-room where it is
           needed.
        2. **Reduction** -- for overage that cannot be covered by reallocation,
           and for any shortfall against the savings goal, the largest
           reducible expenses are surfaced as concrete cut candidates.
        """
        spending = self.spending_by_category()

        over: List[tuple] = []          # (category, overage)
        surplus: Dict[str, float] = {}  # category -> head-room
        for cat, limit in self._budgets.items():
            spent = spending.get(cat, 0.0)
            if spent > limit:
                over.append((cat, _money(spent - limit)))
            elif limit - spent > 0:
                surplus[cat] = _money(limit - spent)

        over.sort(key=lambda item: item[1], reverse=True)
        surplus_sorted = sorted(surplus.items(), key=lambda item: item[1], reverse=True)

        # Stage 1 -- greedy reallocation from the surplus pool.
        surplus_pool = dict(surplus_sorted)
        reallocations: List[Dict] = []
        unfunded: Dict[str, float] = {}
        for cat, overage in over:
            need = overage
            for scat in list(surplus_pool):
                if need <= 0:
                    break
                available = surplus_pool[scat]
                if available <= 0:
                    continue
                move = _money(min(available, need))
                if move <= 0:
                    continue
                reallocations.append({"from": scat, "to": cat, "amount": move})
                surplus_pool[scat] = _money(available - move)
                need = _money(need - move)
            if need > 0:
                unfunded[cat] = need

        messages: List[str] = []
        for r in reallocations:
            messages.append(
                f"Reallocate {r['amount']:,.2f} from '{r['from']}' to "
                f"'{r['to']}' (the group's total budget is unchanged)."
            )

        # Stage 2a -- reductions for overage that reallocation could not cover.
        reduction_suggestions: List[Dict] = []
        for cat, need in unfunded.items():
            picks = self._pick_expenses(self._expenses_in_category(cat), need)
            reduction_suggestions.extend(picks)
            messages.append(
                f"Category '{cat}' is over budget by {need:,.2f} that cannot be "
                f"covered by reallocation; consider trimming the listed expenses."
            )

        # Stage 2b -- reductions to honour the group savings goal.
        total_budget = self.total_budget()
        total_spent = self.total_spent()
        target_max_spend = _money(total_budget - self._savings_goal)
        raw_goal_gap = _money(total_spent - target_max_spend)

        goal_suggestions: List[Dict] = []
        if self._savings_goal > 0 and raw_goal_gap > 0:
            goal_suggestions = self._pick_expenses(self.all_expenses(), raw_goal_gap)
            messages.append(
                f"To reach the savings goal of {self._savings_goal:,.2f} the group "
                f"must cut {raw_goal_gap:,.2f} of spending; the largest reducible "
                f"expenses are listed."
            )
        elif self._savings_goal > 0:
            messages.append(
                f"The group is on track to meet its savings goal of "
                f"{self._savings_goal:,.2f}."
            )

        if not over and not goal_suggestions:
            messages.append("All categories are within budget. No action required.")

        goal_met = True if self._savings_goal == 0 else raw_goal_gap <= 0
        goal_gap = max(raw_goal_gap, 0.0) if self._savings_goal > 0 else 0.0

        return {
            "over_budget": [{"category": c, "overage": o} for c, o in over],
            "surplus": [{"category": c, "amount": a} for c, a in surplus_sorted],
            "reallocations": reallocations,
            "unfunded_overage": unfunded,
            "reduction_suggestions": reduction_suggestions,
            "goal_gap": goal_gap,
            "goal_suggestions": goal_suggestions,
            "goal_met": goal_met,
            "messages": messages,
        }

    # ----------------------- optimization helpers -------------------------- #
    def _expenses_in_category(self, category: str) -> List[Expense]:
        return [e for e in self.all_expenses() if e.category == category]

    @staticmethod
    def _pick_expenses(expenses: List[Expense], target: float) -> List[Dict]:
        """Greedily pick the largest expenses until *target* is covered."""
        picked: List[Dict] = []
        accumulated = 0.0
        for e in sorted(expenses, key=lambda x: x.amount, reverse=True):
            if accumulated >= target:
                break
            picked.append(
                {
                    "user": e.user,
                    "category": e.category,
                    "amount": e.amount,
                    "description": e.description or "(no description)",
                }
            )
            accumulated = _money(accumulated + e.amount)
        return picked

    # ----------------------------- display --------------------------------- #
    def format_dashboard(self) -> str:
        d = self.dashboard()
        lines = ["=" * 64, "GROUP BUDGET DASHBOARD", "=" * 64]
        lines.append(f"Members            : {d['num_users']}")
        lines.append(f"Expenses recorded  : {d['num_expenses']}")
        lines.append(f"Total budget       : {d['total_budget']:>14,.2f}")
        lines.append(f"Total spent        : {d['total_spent']:>14,.2f}")
        lines.append(f"Remaining budget   : {d['remaining_budget']:>14,.2f}")
        lines.append(f"Savings goal       : {d['savings_goal']:>14,.2f}")
        lines.append(
            f"Savings goal status: {'MET' if d['goal_met'] else 'NOT MET':>14}"
        )
        lines.append("-" * 64)
        lines.append("Categories:")
        lines.append(
            f"  {'category':<16}{'limit':>10}{'spent':>10}"
            f"{'remaining':>12}  status"
        )
        for cat, info in d["categories"].items():
            status = "OVER" if info["over_budget"] else "ok"
            lines.append(
                f"  {cat:<16}{info['limit']:>10,.2f}{info['spent']:>10,.2f}"
                f"{info['remaining']:>12,.2f}  {status}"
            )
        lines.append("-" * 64)
        lines.append("Member contributions:")
        if d["users"]:
            for name, info in d["users"].items():
                lines.append(
                    f"  {name:<16}{info['total_spent']:>10,.2f}  "
                    f"({info['share_pct']:.1f}% of spend, "
                    f"{info['num_expenses']} expenses)"
                )
        else:
            lines.append("  (no members yet)")
        lines.append("=" * 64)
        return "\n".join(lines)

    def format_optimization(self) -> str:
        o = self.optimize()
        lines = ["=" * 64, "OPTIMIZATION REPORT", "=" * 64]
        if o["over_budget"]:
            lines.append("Over-budget categories:")
            for item in o["over_budget"]:
                lines.append(
                    f"  - {item['category']}: over by {item['overage']:,.2f}"
                )
        else:
            lines.append("No category is over budget.")
        lines.append("-" * 64)
        lines.append("Recommendations:")
        for msg in o["messages"]:
            lines.append(f"  * {msg}")

        combined: List[Dict] = []
        seen = set()
        for s in o["reduction_suggestions"] + o["goal_suggestions"]:
            key = (s["user"], s["category"], s["amount"], s["description"])
            if key in seen:
                continue
            seen.add(key)
            combined.append(s)
        if combined:
            lines.append("-" * 64)
            lines.append("Candidate expenses to reduce:")
            for s in combined:
                lines.append(
                    f"  - {s['amount']:>10,.2f} | {s['category']:<14} | "
                    f"{s['user']:<10} | {s['description']}"
                )
        lines.append("=" * 64)
        return "\n".join(lines)


# --------------------------------------------------------------------------- #
#  Demonstration
# --------------------------------------------------------------------------- #
def run_demo() -> None:
    """Build a small sample group and print the dashboard + optimization."""
    optimizer = MultiAgentBudgetOptimizer(savings_goal=200.0)

    for name in ("Alice", "Bob", "Carol"):
        optimizer.add_user(name)

    optimizer.set_budget("groceries", 600)
    optimizer.set_budget("entertainment", 300)
    optimizer.set_budget("utilities", 400)
    optimizer.set_budget("transport", 200)

    optimizer.add_expense("Alice", "groceries", 250, "Costco run")
    optimizer.add_expense("Alice", "entertainment", 120, "Concert tickets")
    optimizer.add_expense("Bob", "groceries", 420, "Weekly shopping")
    optimizer.add_expense("Bob", "utilities", 180, "Electricity bill")
    optimizer.add_expense("Carol", "entertainment", 260, "Streaming + games")
    optimizer.add_expense("Carol", "transport", 90, "Fuel")

    print(optimizer.format_dashboard())
    print()
    print(optimizer.format_optimization())


# --------------------------------------------------------------------------- #
#  Unit tests
# --------------------------------------------------------------------------- #
class TestUserManagement(unittest.TestCase):
    def setUp(self) -> None:
        self.opt = MultiAgentBudgetOptimizer()

    def test_add_user(self) -> None:
        self.opt.add_user("Alice")
        self.assertEqual(self.opt.users, ["Alice"])

    def test_add_user_strips_whitespace(self) -> None:
        self.opt.add_user("  Bob  ")
        self.assertEqual(self.opt.users, ["Bob"])

    def test_duplicate_user_rejected(self) -> None:
        self.opt.add_user("Alice")
        with self.assertRaises(UserError):
            self.opt.add_user("Alice")

    def test_invalid_user_name_rejected(self) -> None:
        for bad in ("", "   ", None, 123, 3.5):
            with self.assertRaises(ValidationError):
                self.opt.add_user(bad)

    def test_remove_user(self) -> None:
        self.opt.add_user("Alice")
        self.opt.remove_user("Alice")
        self.assertEqual(self.opt.users, [])

    def test_remove_unknown_user_rejected(self) -> None:
        with self.assertRaises(UserError):
            self.opt.remove_user("Ghost")

    def test_get_unknown_user_rejected(self) -> None:
        with self.assertRaises(UserError):
            self.opt.get_user("Nobody")


class TestBudgetManagement(unittest.TestCase):
    def setUp(self) -> None:
        self.opt = MultiAgentBudgetOptimizer()

    def test_set_and_get_budget_case_insensitive(self) -> None:
        self.opt.set_budget("Groceries", 500)
        self.assertEqual(self.opt.get_budget("groceries"), 500.0)
        self.assertEqual(self.opt.get_budget("GROCERIES"), 500.0)

    def test_set_budget_zero_allowed(self) -> None:
        self.opt.set_budget("misc", 0)
        self.assertEqual(self.opt.get_budget("misc"), 0.0)

    def test_set_budget_negative_rejected(self) -> None:
        with self.assertRaises(ValidationError):
            self.opt.set_budget("groceries", -10)

    def test_set_budget_invalid_amount_rejected(self) -> None:
        for bad in ("abc", None, float("nan"), float("inf"), True):
            with self.assertRaises(ValidationError):
                self.opt.set_budget("groceries", bad)

    def test_set_budget_invalid_category_rejected(self) -> None:
        for bad in ("", "   ", None, 5):
            with self.assertRaises(ValidationError):
                self.opt.set_budget(bad, 100)

    def test_adjust_budget_up_and_down(self) -> None:
        self.opt.set_budget("groceries", 500)
        self.assertEqual(self.opt.adjust_budget("groceries", 100), 600.0)
        self.assertEqual(self.opt.adjust_budget("groceries", -250), 350.0)

    def test_adjust_budget_negative_result_rejected(self) -> None:
        self.opt.set_budget("groceries", 100)
        with self.assertRaises(ValidationError):
            self.opt.adjust_budget("groceries", -200)

    def test_adjust_unknown_category_rejected(self) -> None:
        with self.assertRaises(CategoryError):
            self.opt.adjust_budget("ghost", 10)

    def test_remove_budget(self) -> None:
        self.opt.set_budget("a", 100)
        self.opt.remove_budget("a")
        self.assertEqual(self.opt.categories, [])

    def test_remove_unknown_budget_rejected(self) -> None:
        with self.assertRaises(CategoryError):
            self.opt.remove_budget("ghost")

    def test_total_budget(self) -> None:
        self.opt.set_budget("a", 100)
        self.opt.set_budget("b", 250)
        self.assertEqual(self.opt.total_budget(), 350.0)


class TestExpenses(unittest.TestCase):
    def setUp(self) -> None:
        self.opt = MultiAgentBudgetOptimizer()
        self.opt.add_user("Alice")
        self.opt.set_budget("groceries", 500)

    def test_add_expense(self) -> None:
        e = self.opt.add_expense("Alice", "groceries", 120, "veg")
        self.assertEqual(e.amount, 120.0)
        self.assertEqual(self.opt.category_spent("groceries"), 120.0)

    def test_expense_unknown_user_rejected(self) -> None:
