class TestOptimization(unittest.TestCase):
    def setUp(self) -> None:
        self.opt = MultiAgentBudgetOptimizer()
        self.opt.add_user("Alice")
        self.opt.add_user("Bob")
        self.opt.set_budget("groceries", 300)
        self.opt.set_budget("entertainment", 200)
        self.opt.set_budget("utilities", 400)

    def test_reallocation_fully_covers_overage(self) -> None:
        self.opt.add_expense("Alice", "groceries", 400)   # over by 100
        self.opt.add_expense("Bob", "utilities", 100)     # surplus 300
        result = self.opt.optimize()
        self.assertTrue(any(r["to"] == "groceries" for r in result["reallocations"]))
        self.assertEqual(result["unfunded_overage"], {})

    def test_unfunded_overage_creates_reductions(self) -> None:
        # Spend beyond the entire group budget so surplus cannot cover it.
        self.opt.add_expense("Alice", "groceries", 1000)  # over by 700
        result = self.opt.optimize()                       # surplus only 600
        self.assertIn("groceries", result["unfunded_overage"])
        self.assertGreaterEqual(len(result["reduction_suggestions"]), 1)

    def test_savings_goal_gap_suggestions(self) -> None:
        self.opt.set_savings_goal(500)                     # target max spend 400
        self.opt.add_expense("Alice", "groceries", 300)
        self.opt.add_expense("Bob", "utilities", 300)      # spent 600 -> gap 200
        result = self.opt.optimize()
        self.assertGreater(result["goal_gap"], 0)
        self.assertFalse(result["goal_met"])
        self.assertGreaterEqual(len(result["goal_suggestions"]), 1)

    def test_savings_goal_on_track(self) -> None:
        self.opt.set_savings_goal(100)
        self.opt.add_expense("Alice", "groceries", 100)
        result = self.opt.optimize()
        self.assertTrue(result["goal_met"])
        self.assertEqual(result["goal_gap"], 0.0)

    def test_all_within_budget_message(self) -> None:
        self.opt.add_expense("Alice", "groceries", 100)
        result = self.opt.optimize()
        self.assertEqual(result["over_budget"], [])
        self.assertTrue(any("within budget" in m for m in result["messages"]))

    def test_format_optimization_runs(self) -> None:
        self.opt.add_expense("Alice", "groceries", 400)
        self.opt.add_expense("Bob", "utilities", 50)
        text = self.opt.format_optimization()
        self.assertIn("OPTIMIZATION REPORT", text)


